public class ArithmeticOperators {
  public static void main(String[] args) {
    int a = 10;
    int b = 3;
    System.out.println("Toplama: " + (a + b)); // 13
    System.out.println("Çıxma: " + (a - b)); // 7
    System.out.println("Vurma: " + (a * b)); // 30
    System.out.println("Bölmə: " + (a / b)); // 3
    System.out.println("Qalıq: " + (a % b)); // 1
    a++;
    System.out.println("Artırma: " + a); // 11
    b--;
    System.out.println("Azaltma: " + b); // 2
  }
}
// Çıxış: Toplama: 13
// Çıxma: 7
// Vurma: 30
// Bölmə: 3
// Qalıq: 1
// Artırma: 11
// Azaltma: 2

public class ComparisonOperators {
  public static void main(String[] args) {
    int x = 5;
    int y = 10;
    System.out.println("Bərabərdir: " + (x == y)); // false
    System.out.println("Bərabər deyil: " + (x != y)); // true
    System.out.println("Böyükdür: " + (x > y)); // false
    System.out.println("Kiçikdir: " + (x < y)); // true
    System.out.println("Böyük və ya bərabər: " + (x >= y)); // false
    System.out.println("Kiçik və ya bərabər: " + (x <= y)); // true
  }
}
// Çıxış: Bərabərdir: false
// Bərabər deyil: true
// Böyükdür: false
// Kiçikdir: true
// Böyük və ya bərabər: false
// Kiçik və ya bərabər: true

public class LogicalOperators {
  public static void main(String[] args) {
    boolean isStudent = true;
    boolean hasPass = false;
    System.out.println("Və: " + (isStudent && hasPass)); // false
    System.out.println("Və ya: " + (isStudent || hasPass)); // true
    System.out.println("Deyil: " + (!isStudent)); // false
  }
}
// Çıxış: Və: false
// Və ya: true
// Deyil: false

public class AssignmentOperators {
  public static void main(String[] args) {
    int number = 10;
    number += 5; // number = number + 5
    System.out.println("Toplama təyinatı: " + number); // 15
    number -= 3; // number = number - 3
    System.out.println("Çıxma təyinatı: " + number); // 12
    number *= 2; // number = number * 2
    System.out.println("Vurma təyinatı: " + number); // 24
    number /= 4; // number = number / 4
    System.out.println("Bölmə təyinatı: " + number); // 6
    number %= 5; // number = number % 5
    System.out.println("Qalıq təyinatı: " + number); // 1
  }
}
// Çıxış: Toplama təyinatı: 15
// Çıxma təyinatı: 12
// Vurma təyinatı: 24
// Bölmə təyinatı: 6
// Qalıq təyinatı: 1

public class BitOperators {
  public static void main(String[] args) {
    int a = 5; // 0101 (ikili)
    int b = 3; // 0011 (ikili)
    System.out.println("Bit Və: " + (a & b)); // 0001 -> 1
    System.out.println("Bit Və ya: " + (a | b)); // 0111 -> 7
    System.out.println("Bit XOR: " + (a ^ b)); // 0110 -> 6
    System.out.println("Bit Tərsi: " + (~a)); // 1010... -> -6
    System.out.println("Sola sürüşdürmə: " + (a << 1)); // 1010 -> 10
    System.out.println("Sağa sürüşdürmə: " + (a >> 1)); // 0010 -> 2
  }
}
// Çıxış: Bit Və: 1
// Bit Və ya: 7
// Bit XOR: 6
// Bit Tərsi: -6
// Sola sürüşdürmə: 10
// Sağa sürüşdürmə: 2

public class OtherOperators {
  public static void main(String[] args) {
    String text = "Hello";
    System.out.println("String tipi: " + (text instanceof String)); // true

    int score = 85;
    String result = (score >= 60) ? "Passed" : "Failed"; // Üçlü operator
    System.out.println("Result: " + result); // Passed
  }
}
// Çıxış: String tipi: true
// Result: Passed

public class OperatorPrecedence {
  public static void main(String[] args) {
    int result = 2 + 3 * 4; // 3 * 4 = 12, sonra 2 + 12 = 14
    System.out.println("Nəticə: " + result); // 14
    result = (2 + 3) * 4; // 2 + 3 = 5, sonra 5 * 4 = 20
    System.out.println("Mötərizə ilə: " + result); // 20
  }
}
// Çıxış: Nəticə: 14
// Mötərizə ilə: 20

public class OrderCalculation {
  public static void main(String[] args) {
    double price = 100.0;
    int quantity = 3;
    double discountRate = 0.1; // 10% endirim
    double total = price * quantity; // Aritmetik
    total -= total * discountRate; // Təyinat
    boolean isValidOrder = total > 0 && quantity > 0; // Məntiqi
    System.out.println("Total: " + total + ", Valid Order: " + isValidOrder);
    String status = total >= 200 ? "Free Shipping" : "Shipping Fee"; // Üçlü
    System.out.println("Status: " + status);
  }
}
// Çıxış: Total: 270.0, Valid Order: true
// Status: Free Shipping

